215→/// Global Ghostty application instance. One per process.
216→pub struct GhosttyApp {
217→    inner: *mut c_void,
218→}
219→
220→// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
221→unsafe impl Send for GhosttyApp {}
222→unsafe impl Sync for GhosttyApp {}
223→
224→impl GhosttyApp {
225→    /// Initialize libghostty and create the app with the user's default config.
226→    pub fn new() -> Result<Self, String> {
227→        unsafe {
228→            // Initialize the library
229→            let ret = ghostty_init(0, ptr::null_mut());
230→            if ret != 0 {
231→                return Err(format!("ghostty_init failed with code {}", ret));
232→            }
233→
234→            // Create and load config (reads ~/.config/ghostty/config automatically)
235→            let config = ghostty_config_new();
236→            if config.is_null() {
237→                return Err("ghostty_config_new returned null".into());
238→            }
239→            ghostty_config_load_default_files(config);
240→            ghostty_config_finalize(config);
241→
242→            // Set up runtime callbacks
243→            let runtime_config = GhosttyRuntimeConfig {
244→                userdata: ptr::null_mut(),
245→                supports_selection_clipboard: false,
246→                wakeup_cb: runtime_wakeup,
247→                action_cb: runtime_action,
248→                read_clipboard_cb: runtime_read_clipboard,
249→                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
250→                write_clipboard_cb: runtime_write_clipboard,
251→                close_surface_cb: runtime_close_surface,
252→            };
253→
254→            let app = ghostty_app_new(&runtime_config, config);
255→            if app.is_null() {
256→                ghostty_config_free(config);
257→                return Err("ghostty_app_new returned null".into());
258→            }
259→
260→            Ok(Self { inner: app })
261→        }
262→    }
263→
264→    /// Pump the ghostty event loop. Call from a timer or run loop.
265→    pub fn tick(&self) -> bool {
266→        unsafe { ghostty_app_tick(self.inner) }
267→    }
268→
269→    pub fn raw(&self) -> *mut c_void {
270→        self.inner
271→    }
272→}
273→
274→impl Drop for GhosttyApp {
275→    fn drop(&mut self) {
276→        if !self.inner.is_null() {
277→            unsafe { ghostty_app_free(self.inner) };
278→        }
279→    }
280→}
