282→/// A terminal surface backed by libghostty. Renders to a Metal layer.
283→pub struct GhosttySurface {
284→    inner: *mut c_void,
285→    // Keep CStrings alive for the lifetime of the surface
286→    _working_dir: Option<CString>,
287→    _command: Option<CString>,
288→}
289→
290→unsafe impl Send for GhosttySurface {}
291→unsafe impl Sync for GhosttySurface {}
292→
293→impl GhosttySurface {
294→    /// Create a new surface attached to the given NSView.
295→    pub fn new(
296→        app: &GhosttyApp,
297→        nsview: *mut c_void,
298→        working_dir: Option<&str>,
299→        command: Option<&str>,
300→        scale_factor: f64,
301→    ) -> Result<Self, String> {
302→        let working_dir_c = working_dir.map(|s| CString::new(s).unwrap());
303→        let command_c = command.map(|s| CString::new(s).unwrap());
304→
305→        let config = GhosttySurfaceConfig {
306→            platform_tag: GhosttyPlatform::MacOS,
307→            platform: GhosttyPlatformUnion { nsview },
308→            userdata: ptr::null_mut(),
309→            scale_factor,
310→            font_size: 0.0, // 0 = use config default
311→            working_directory: working_dir_c
312→                .as_ref()
313→                .map_or(ptr::null(), |s| s.as_ptr()),
314→            command: command_c
315→                .as_ref()
316→                .map_or(ptr::null(), |s| s.as_ptr()),
317→            env_vars: ptr::null_mut(),
318→            env_var_count: 0,
319→            initial_input: ptr::null(),
320→            wait_after_command: false,
321→            context: GhosttySurfaceContext::Embedded,
322→        };
323→
324→        let surface = unsafe { ghostty_surface_new(app.raw(), &config) };
325→        if surface.is_null() {
326→            return Err("ghostty_surface_new returned null".into());
327→        }
328→
329→        Ok(Self {
330→            inner: surface,
331→            _working_dir: working_dir_c,
332→            _command: command_c,
333→        })
334→    }
335→
336→    pub fn draw(&self) {
337→        unsafe { ghostty_surface_draw(self.inner) };
338→    }
339→
340→    pub fn set_size(&self, width: u32, height: u32) {
341→        unsafe { ghostty_surface_set_size(self.inner, width, height) };
342→    }
343→
344→    pub fn set_focus(&self, focused: bool) {
345→        unsafe { ghostty_surface_set_focus(self.inner, focused) };
346→    }
347→
348→    /// Send text input to the surface (for injecting prompts, etc.)
349→    pub fn send_text(&self, text: &str) {
350→        let c_text = CString::new(text).unwrap_or_default();
351→        unsafe {
352→            ghostty_surface_text(self.inner, c_text.as_ptr(), text.len());
353→        }
354→    }
355→
356→    pub fn key(&self, key: GhosttyInputKey) -> bool {
357→        unsafe { ghostty_surface_key(self.inner, key) }
358→    }
359→
360→    pub fn mouse_button(
361→        &self,
362→        state: GhosttyMouseState,
363→        button: GhosttyMouseButton,
364→        mods: GhosttyInputMods,
365→    ) -> bool {
366→        unsafe { ghostty_surface_mouse_button(self.inner, state, button, mods) }
367→    }
368→
369→    pub fn mouse_pos(&self, x: f64, y: f64, mods: GhosttyInputMods) {
370→        unsafe { ghostty_surface_mouse_pos(self.inner, x, y, mods) };
371→    }
372→
373→    pub fn mouse_scroll(&self, dx: f64, dy: f64, precision: bool) {
374→        let mods = GhosttyScrollMods { precision };
375→        unsafe { ghostty_surface_mouse_scroll(self.inner, dx, dy, mods) };
376→    }
377→}
378→
379→impl Drop for GhosttySurface {
380→    fn drop(&mut self) {
381→        if !self.inner.is_null() {
382→            unsafe { ghostty_surface_free(self.inner) };
383→        }
384→    }
385→}
386→
387→// ---------------------------------------------------------------------------
388→// Shared state for the ghostty bridge
389→// ---------------------------------------------------------------------------
390→
391→pub struct GhosttyState {
392→    pub app: Option<GhosttyApp>,
393→    pub surfaces: std::collections::HashMap<String, SurfaceEntry>,
394→}
395→
396→pub struct SurfaceEntry {
397→    pub surface: GhosttySurface,
398→    pub overlay: overlay::GhosttyOverlay,
399→}
400→
401→impl GhosttyState {
402→    pub fn new() -> Self {
403→        Self {
404→            app: None,
405→            surfaces: std::collections::HashMap::new(),
406→        }
407→    }
408→
409→    /// Lazily initialize the GhosttyApp on first surface creation.
410→    pub fn ensure_app(&mut self) -> Result<&GhosttyApp, String> {
411→        if self.app.is_none() {
412→            self.app = Some(GhosttyApp::new()?);
413→        }
414→        Ok(self.app.as_ref().unwrap())
415→    }
416→}
417→
418→pub type SharedGhosttyState = Arc<Mutex<GhosttyState>>;
419→
420→pub fn new_shared_state() -> SharedGhosttyState {
421→    Arc::new(Mutex::new(GhosttyState::new()))
422→}
423→
424→// ---------------------------------------------------------------------------
425→// Runtime callbacks (C ABI)
426→// ---------------------------------------------------------------------------
427→
428→extern "C" fn runtime_wakeup(_userdata: *mut c_void) {
429→    // Trigger a redraw on the main thread. For now, this is a no-op
430→    // since we drive rendering from the Tauri event loop.
431→}
432→
433→extern "C" fn runtime_action(
434→    _app: *mut c_void,
435→    _target: GhosttyTarget,
436→    _action: GhosttyAction,
437→) -> bool {
438→    // Handle ghostty actions (new tab, close, etc.)
439→    // Return false to indicate we didn't handle it
440→    false
441→}
442→
443→extern "C" fn runtime_read_clipboard(
444→    _userdata: *mut c_void,
445→    _clipboard: GhosttyClipboard,
446→    _state: *mut c_void,
447→) -> bool {
448→    // TODO: integrate with system clipboard via Tauri
449→    false
450→}
451→
452→extern "C" fn runtime_confirm_read_clipboard(
453→    _userdata: *mut c_void,
454→    _content: *const c_char,
455→    _state: *mut c_void,
456→    _request: GhosttyClipboardRequest,
457→) {
458→    // Auto-confirm clipboard reads for embedded context
