pub mod commands;
pub mod overlay;

use std::ffi::{c_char, c_void, CString};
use std::ptr;
use std::sync::{Arc, Mutex};

// ---------------------------------------------------------------------------
// FFI declarations matching vendor/ghostty/ghostty.h
// ---------------------------------------------------------------------------

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyPlatform {
    MacOS = 0,
    IOS = 1,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyClipboard {
    Standard = 0,
    Selection = 1,
    Primary = 2,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyClipboardRequest {
    Paste = 0,
    Osc52Read = 1,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyMouseState {
    Press = 0,
    Release = 1,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyMouseButton {
    Left = 0,
    Right = 1,
    Middle = 2,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyInputMods {
    None = 0,
    Shift = 1,
    Ctrl = 2,
    Alt = 4,
    Super = 8,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttySurfaceContext {
    Window = 0,
    Embedded = 1,
}

#[repr(C)]
pub struct GhosttyEnvVar {
    pub key: *const c_char,
    pub value: *const c_char,
}

#[repr(C)]
pub struct GhosttyClipboardContent {
    pub data: *const c_char,
    pub len: usize,
}

#[repr(C)]
pub struct GhosttyScrollMods {
    pub precision: bool,
}

#[repr(C)]
pub struct GhosttyInputKey {
    pub keycode: u32,
    pub text: *const c_char,
    pub text_len: usize,
    pub mods: GhosttyInputMods,
    pub composing: bool,
}

// Opaque action/target structs — passed through callbacks, not inspected
#[repr(C)]
pub struct GhosttyTarget {
    _opaque: [u8; 0],
}

#[repr(C)]
pub struct GhosttyAction {
    _opaque: [u8; 0],
}

// Callback types
type WakeupCb = extern "C" fn(userdata: *mut c_void);
type ActionCb = extern "C" fn(
    app: *mut c_void,
    target: GhosttyTarget,
    action: GhosttyAction,
) -> bool;
type ReadClipboardCb =
    extern "C" fn(userdata: *mut c_void, clipboard: GhosttyClipboard, state: *mut c_void) -> bool;
type ConfirmReadClipboardCb = extern "C" fn(
    userdata: *mut c_void,
    content: *const c_char,
    state: *mut c_void,
    request: GhosttyClipboardRequest,
);
type WriteClipboardCb = extern "C" fn(
    userdata: *mut c_void,
    clipboard: GhosttyClipboard,
    content: *const GhosttyClipboardContent,
    content_len: usize,
    confirm: bool,
);
type CloseSurfaceCb = extern "C" fn(userdata: *mut c_void, process_alive: bool);

#[repr(C)]
pub struct GhosttyRuntimeConfig {
    pub userdata: *mut c_void,
    pub supports_selection_clipboard: bool,
    pub wakeup_cb: WakeupCb,
    pub action_cb: ActionCb,
    pub read_clipboard_cb: ReadClipboardCb,
    pub confirm_read_clipboard_cb: ConfirmReadClipboardCb,
    pub write_clipboard_cb: WriteClipboardCb,
    pub close_surface_cb: CloseSurfaceCb,
}

#[repr(C)]
pub union GhosttyPlatformUnion {
    pub nsview: *mut c_void,
    pub uiview: *mut c_void,
}

#[repr(C)]
pub struct GhosttySurfaceConfig {
    pub platform_tag: GhosttyPlatform,
    pub platform: GhosttyPlatformUnion,
    pub userdata: *mut c_void,
    pub scale_factor: f64,
    pub font_size: f32,
    pub working_directory: *const c_char,
    pub command: *const c_char,
    pub env_vars: *mut GhosttyEnvVar,
    pub env_var_count: usize,
    pub initial_input: *const c_char,
    pub wait_after_command: bool,
    pub context: GhosttySurfaceContext,
}

extern "C" {
    fn ghostty_init(argc: usize, argv: *mut *mut c_char) -> i32;
    fn ghostty_config_new() -> *mut c_void;
    fn ghostty_config_load_default_files(config: *mut c_void);
    fn ghostty_config_finalize(config: *mut c_void);
    fn ghostty_config_free(config: *mut c_void);
    fn ghostty_config_set(config: *mut c_void, key: *const c_char, value: *const c_char);
    fn ghostty_app_new(
        runtime_config: *const GhosttyRuntimeConfig,
        config: *mut c_void,
    ) -> *mut c_void;
    fn ghostty_app_free(app: *mut c_void);
    fn ghostty_app_tick(app: *mut c_void) -> bool;
    fn ghostty_surface_new(
        app: *mut c_void,
        config: *const GhosttySurfaceConfig,
    ) -> *mut c_void;
    fn ghostty_surface_free(surface: *mut c_void);
    fn ghostty_surface_draw(surface: *mut c_void);
    fn ghostty_surface_set_size(surface: *mut c_void, width: u32, height: u32);
    fn ghostty_surface_set_focus(surface: *mut c_void, focused: bool);
    fn ghostty_surface_key(surface: *mut c_void, key: GhosttyInputKey) -> bool;
    fn ghostty_surface_text(surface: *mut c_void, text: *const c_char, len: usize);
    fn ghostty_surface_mouse_button(
        surface: *mut c_void,
        state: GhosttyMouseState,
        button: GhosttyMouseButton,
        mods: GhosttyInputMods,
    ) -> bool;
    fn ghostty_surface_mouse_pos(
        surface: *mut c_void,
        x: f64,
        y: f64,
        mods: GhosttyInputMods,
    );
    fn ghostty_surface_mouse_scroll(
        surface: *mut c_void,
        dx: f64,
        dy: f64,
        mods: GhosttyScrollMods,
    );
}

// ---------------------------------------------------------------------------
// Safe Rust wrappers
// ---------------------------------------------------------------------------

/// Global Ghostty application instance. One per process.
pub struct GhosttyApp {
    inner: *mut c_void,
}

// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
unsafe impl Send for GhosttyApp {}
unsafe impl Sync for GhosttyApp {}

impl GhosttyApp {
    /// Initialize libghostty and create the app with the user's default config.
    pub fn new() -> Result<Self, String> {
        unsafe {
            // Initialize the library
            let ret = ghostty_init(0, ptr::null_mut());
            if ret != 0 {
                return Err(format!("ghostty_init failed with code {}", ret));
            }

            // Create and load config (reads ~/.config/ghostty/config automatically)
            let config = ghostty_config_new();
            if config.is_null() {
                return Err("ghostty_config_new returned null".into());
            }
            ghostty_config_load_default_files(config);
            ghostty_config_finalize(config);

            // Set up runtime callbacks
            let runtime_config = GhosttyRuntimeConfig {
                userdata: ptr::null_mut(),
                supports_selection_clipboard: false,
                wakeup_cb: runtime_wakeup,
                action_cb: runtime_action,
                read_clipboard_cb: runtime_read_clipboard,
                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
                write_clipboard_cb: runtime_write_clipboard,
                close_surface_cb: runtime_close_surface,
            };

            let app = ghostty_app_new(&runtime_config, config);
            if app.is_null() {
                ghostty_config_free(config);
                return Err("ghostty_app_new returned null".into());
            }

            Ok(Self { inner: app })
        }
    }

    /// Pump the ghostty event loop. Call from a timer or run loop.
    pub fn tick(&self) -> bool {
        unsafe { ghostty_app_tick(self.inner) }
    }

    pub fn raw(&self) -> *mut c_void {
        self.inner
    }
}

impl Drop for GhosttyApp {
    fn drop(&mut self) {
        if !self.inner.is_null() {
            unsafe { ghostty_app_free(self.inner) };
        }
    }
}

/// A terminal surface backed by libghostty. Renders to a Metal layer.
pub struct GhosttySurface {
    inner: *mut c_void,
    // Keep CStrings alive for the lifetime of the surface
    _working_dir: Option<CString>,
    _command: Option<CString>,
}

unsafe impl Send for GhosttySurface {}
unsafe impl Sync for GhosttySurface {}

impl GhosttySurface {
    /// Create a new surface attached to the given NSView.
    pub fn new(
        app: &GhosttyApp,
        nsview: *mut c_void,
        working_dir: Option<&str>,
        command: Option<&str>,
        scale_factor: f64,
    ) -> Result<Self, String> {
        let working_dir_c = working_dir.map(|s| CString::new(s).unwrap());
        let command_c = command.map(|s| CString::new(s).unwrap());

        let config = GhosttySurfaceConfig {
            platform_tag: GhosttyPlatform::MacOS,
            platform: GhosttyPlatformUnion { nsview },
            userdata: ptr::null_mut(),
            scale_factor,
            font_size: 0.0, // 0 = use config default
            working_directory: working_dir_c
                .as_ref()
                .map_or(ptr::null(), |s| s.as_ptr()),
            command: command_c
                .as_ref()
                .map_or(ptr::null(), |s| s.as_ptr()),
            env_vars: ptr::null_mut(),
            env_var_count: 0,
            initial_input: ptr::null(),
            wait_after_command: false,
            context: GhosttySurfaceContext::Embedded,
        };

        let surface = unsafe { ghostty_surface_new(app.raw(), &config) };
        if surface.is_null() {
            return Err("ghostty_surface_new returned null".into());
        }

        Ok(Self {
            inner: surface,
            _working_dir: working_dir_c,
            _command: command_c,
        })
    }

    pub fn draw(&self) {
        unsafe { ghostty_surface_draw(self.inner) };
    }

    pub fn set_size(&self, width: u32, height: u32) {
        unsafe { ghostty_surface_set_size(self.inner, width, height) };
    }

    pub fn set_focus(&self, focused: bool) {
        unsafe { ghostty_surface_set_focus(self.inner, focused) };
    }

    /// Send text input to the surface (for injecting prompts, etc.)
    pub fn send_text(&self, text: &str) {
        let c_text = CString::new(text).unwrap_or_default();
        unsafe {
            ghostty_surface_text(self.inner, c_text.as_ptr(), text.len());
        }
    }

    pub fn key(&self, key: GhosttyInputKey) -> bool {
        unsafe { ghostty_surface_key(self.inner, key) }
    }

    pub fn mouse_button(
        &self,
        state: GhosttyMouseState,
        button: GhosttyMouseButton,
        mods: GhosttyInputMods,
    ) -> bool {
        unsafe { ghostty_surface_mouse_button(self.inner, state, button, mods) }
    }

    pub fn mouse_pos(&self, x: f64, y: f64, mods: GhosttyInputMods) {
        unsafe { ghostty_surface_mouse_pos(self.inner, x, y, mods) };
    }

    pub fn mouse_scroll(&self, dx: f64, dy: f64, precision: bool) {
        let mods = GhosttyScrollMods { precision };
        unsafe { ghostty_surface_mouse_scroll(self.inner, dx, dy, mods) };
    }
}

impl Drop for GhosttySurface {
    fn drop(&mut self) {
        if !self.inner.is_null() {
            unsafe { ghostty_surface_free(self.inner) };
        }
    }
}

// ---------------------------------------------------------------------------
// Shared state for the ghostty bridge
// ---------------------------------------------------------------------------

pub struct GhosttyState {
    pub app: Option<GhosttyApp>,
    pub surfaces: std::collections::HashMap<String, SurfaceEntry>,
}

pub struct SurfaceEntry {
    pub surface: GhosttySurface,
    pub overlay: overlay::GhosttyOverlay,
}

impl GhosttyState {
    pub fn new() -> Self {
        Self {
            app: None,
            surfaces: std::collections::HashMap::new(),
        }
    }

    /// Lazily initialize the GhosttyApp on first surface creation.
    pub fn ensure_app(&mut self) -> Result<&GhosttyApp, String> {
        if self.app.is_none() {
            self.app = Some(GhosttyApp::new()?);
        }
        Ok(self.app.as_ref().unwrap())
    }
}

pub type SharedGhosttyState = Arc<Mutex<GhosttyState>>;

pub fn new_shared_state() -> SharedGhosttyState {
    Arc::new(Mutex::new(GhosttyState::new()))
}

// ---------------------------------------------------------------------------
// Runtime callbacks (C ABI)
// ---------------------------------------------------------------------------

extern "C" fn runtime_wakeup(_userdata: *mut c_void) {
    // Trigger a redraw on the main thread. For now, this is a no-op
    // since we drive rendering from the Tauri event loop.
}

extern "C" fn runtime_action(
    _app: *mut c_void,
    _target: GhosttyTarget,
    _action: GhosttyAction,
) -> bool {
    // Handle ghostty actions (new tab, close, etc.)
    // Return false to indicate we didn't handle it
    false
}

extern "C" fn runtime_read_clipboard(
    _userdata: *mut c_void,
    _clipboard: GhosttyClipboard,
    _state: *mut c_void,
) -> bool {
    // TODO: integrate with system clipboard via Tauri
    false
}

extern "C" fn runtime_confirm_read_clipboard(
    _userdata: *mut c_void,
    _content: *const c_char,
    _state: *mut c_void,
    _request: GhosttyClipboardRequest,
) {
    // Auto-confirm clipboard reads for embedded context
}

extern "C" fn runtime_write_clipboard(
    _userdata: *mut c_void,
    _clipboard: GhosttyClipboard,
    _content: *const GhosttyClipboardContent,
    _content_len: usize,
    _confirm: bool,
) {
    // TODO: write to system clipboard via Tauri
}

extern "C" fn runtime_close_surface(_userdata: *mut c_void, _process_alive: bool) {
    // Surface closed — the frontend will handle cleanup via destroy_surface
}

