use std::ffi::c_void;

use objc2::rc::Retained;
use objc2::runtime::AnyObject;
use objc2::{msg_send, MainThreadMarker};
use objc2_app_kit::{NSView, NSWindow};
use objc2_quartz_core::CAMetalLayer;

/// Manages a native NSView overlay positioned on top of the Tauri webview.
/// The overlay hosts a CAMetalLayer that libghostty renders into via Metal.
pub struct GhosttyOverlay {
    /// The NSView that contains the Metal layer. libghostty renders into this.
    view: Retained<NSView>,
    /// Track visibility so we avoid redundant show/hide calls.
    visible: bool,
}

// SAFETY: NSView operations are dispatched on the main thread via objc2.
// The overlay is only mutated through Mutex<GhosttyState>.
unsafe impl Send for GhosttyOverlay {}
unsafe impl Sync for GhosttyOverlay {}

impl GhosttyOverlay {
    /// Create a new overlay NSView and add it as a subview of the given window.
    ///
    /// # Safety
    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
        // We must be on the main thread to create NSView
        let mtm = MainThreadMarker::new()
            .ok_or_else(|| "Must be called on the main thread".to_string())?;

        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
        let content_view = window
            .contentView()
            .ok_or_else(|| "Window has no contentView".to_string())?;

        // Create the overlay NSView
        let frame = content_view.frame();
        let view = NSView::initWithFrame(mtm.alloc(), frame);

        // Set up a CAMetalLayer for GPU rendering
        {
            let metal_layer = CAMetalLayer::new();

            // Configure the layer for ghostty's Metal rendering
            let layer_ref: &objc2_quartz_core::CALayer = &metal_layer;
            view.setWantsLayer(true);
            view.setLayer(Some(layer_ref));
        }

        // Add as subview — on top of the webview content
        content_view.addSubview(&view);

        // Start hidden until explicitly shown
        view.setHidden(true);

        Ok(Self {
            view,
            visible: false,
        })
    }

    /// Returns the raw NSView pointer for passing to libghostty's surface config.
    pub fn nsview_ptr(&self) -> *mut c_void {
        let view_ref: &NSView = &self.view;
        view_ref as *const NSView as *mut c_void
    }

    /// Reposition and resize the overlay to match the terminal panel in the webview.
    ///
    /// Coordinates come from the frontend (top-left origin, CSS pixels).
    /// macOS NSView uses bottom-left origin, so we flip Y.
    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
        if let Some(superview) = unsafe { self.view.superview() } {
            let parent_height = superview.frame().size.height;
            // Convert from top-left (web) to bottom-left (macOS) origin
            let flipped_y = parent_height - y - height;

            let frame = objc2_foundation::NSRect::new(
                objc2_foundation::NSPoint::new(x, flipped_y),
                objc2_foundation::NSSize::new(width, height),
            );
            self.view.setFrame(frame);
        }
    }

    /// Show or hide the overlay.
    pub fn set_visible(&mut self, visible: bool) {
        if self.visible != visible {
            self.view.setHidden(!visible);
            self.visible = visible;
        }
    }

    /// Whether the overlay is currently visible.
    pub fn is_visible(&self) -> bool {
        self.visible
    }

    /// Make the overlay the first responder (receive keyboard input).
    pub fn focus(&self) {
        unsafe {
            if let Some(window) = self.view.window() {
                let _: bool = msg_send![&*window, makeFirstResponder: &*self.view];
            }
        }
    }
}

impl Drop for GhosttyOverlay {
    fn drop(&mut self) {
        // Remove from superview to clean up
        self.view.removeFromSuperview();
    }
}

/// Get the raw NSWindow pointer from a Tauri webview window.
pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
    #[cfg(target_os = "macos")]
    {
        use raw_window_handle::{HasWindowHandle, RawWindowHandle};

        let handle = window
            .window_handle()
            .map_err(|e| format!("Failed to get window handle: {}", e))?;

        match handle.as_raw() {
            RawWindowHandle::AppKit(handle) => {
                // ns_view is the content view — we need the window.
                // Get the window from the view.
                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
                let ns_window: *mut c_void = unsafe {
                    msg_send![ns_view as *mut AnyObject, window]
                };
                Ok(ns_window)
            }
            _ => Err("Expected AppKit window handle on macOS".into()),
        }
    }

    #[cfg(not(target_os = "macos"))]
    {
        let _ = window;
        Err("NSView overlay is only supported on macOS".into())
    }
}

